@import (reference) "../style/themes/default.less";

.am-vtabs {
  width: 100vw;
  height: 100vh;
  display: flex;
  flex-direction: row;

  &-bar {
    width: @size-15 * 2;
    overflow: hidden;
    &-line {
      position: absolute;
      left: 0;
      top: @h-spacing-large;
      bottom: @h-spacing-large;
      width: 6 * @pixelSize;
      overflow: hidden;
      font-size: 0;
      border-radius: @corner-radius-circle;
      &-radius {
        position: absolute;
        right: 0;
        width: @size-2;
        height: @size-2;
        border-radius: @corner-radius-circle;
        overflow: hidden;
        font-size: 0;
        &__top {
          top: -@size-2;
        }
        &__bottom {
          bottom: -@size-2;
        }
      }
    }
    &-placehold {
      flex: 1 1 0%;
    }
  }

  &-bar-content {
    display: flex;
    flex-direction: column;
    height: 100%;
    width: @size-15 * 2;
    &::-webkit-scrollbar {
      display: none;
    }
  }

  &-bar-tab {
    position: relative;
    box-sizing: border-box;
    width: @size-15 * 2;
    padding: @h-spacing-large @size-6;
    text-align: center;
