      opacity: 0.6;
    }
    &__active {
      font-size: @font-size-subtitle;
      font-size: var(--am-vtabs-fontSize-active, @font-size-subtitle);
    }
    &__same {
      font-size: @font-size-content;
      font-size: var(--am-vtabs-fontSize-same, @font-size-content);
