      fill: @c-text;
      [data-prefers-color='dark'] & {
        fill: @c-text-dark;
      }
    }

    [data-prefers-color='dark'] & {
      border-color: @c-btn-border-dark;
      background-color: @c-bg-dark;
    }
  }

  &-switch {
    [data-mode='doc'] & {
      display: flex;
      button + button {
        margin-left: 4px;
      }
    }

    @media @mobile {
      display: flex;
      button + button {
        margin-left: 10px;
      }
    }

    &-active {
      .@{prefix}-menu & {
        border-color: @c-primary;
        [data-prefers-color='dark'] & {
          border-color: @c-primary-dark;
        }
      }
    }

    [data-mode='doc'][data-mobile-show='true'] & {
      margin-bottom: 10px;
    }

    button {
      z-index: 102;
    }

