@import (reference) '../../style/themes/index';

@drawer-prefix-cls: ~'@{ant-prefix}-drawer';

.panel-motion {
  &-enter,
  &-appear,
  &-leave {
    &-start {
      transition: none;
    }

    &-active {
      transition: all @animation-duration-slow;
    }
  }
}

.@{drawer-prefix-cls} {
  // ======================== Mask ========================
  &-mask-motion {
    &-enter,
    &-appear,
    &-leave {
      &-active {
        transition: all @animation-duration-slow;
      }
    }

    &-enter,
    &-appear {
      opacity: 0;

      &-active {
        opacity: 1;
      }
    }

    &-leave {
      opacity: 1;

      &-active {
        opacity: 0;
      }
    }
  }

  // ======================= Panel ========================
  &-panel-motion {
    // Left
    &-left {
      .panel-motion();

      &-enter,
      &-appear {
        &-start {
          transform: translateX(-100%) !important;
        }

        &-active {
          transform: translateX(0);
        }
      }

      &-leave {
        transform: translateX(0);

        &-active {
          transform: translateX(-100%);
        }
      }
    }

    // Right
    &-right {
      .panel-motion();

      &-enter,
      &-appear {
        &-start {
          transform: translateX(100%) !important;
        }

        &-active {
          transform: translateX(0);
        }
      }

      &-leave {
        transform: translateX(0);

        &-active {
          transform: translateX(100%);
        }
      }
    }

    // Top
    &-top {
      .panel-motion();

      &-enter,
      &-appear {
        &-start {
          transform: translateY(-100%) !important;
        }

        &-active {
          transform: translateY(0);
        }
      }

      &-leave {
        transform: translateY(0);

        &-active {
          transform: translateY(-100%);
        }
      }
    }

    // Bottom
    &-bottom {
      .panel-motion();

      &-enter,
      &-appear {
        &-start {
          transform: translateY(100%) !important;
        }

        &-active {
          transform: translateY(0);
        }
      }

      &-leave {
        transform: translateY(0);

        &-active {
          transform: translateY(100%);
        }
      }
    }
  }
}

@resizable-prefix-cls: ~'nz-resizable';

.@{resizable-prefix-cls} {
  &-preview {
    position: absolute;
    top: 0;
    left: 0;
    z-index: 8;
    border: 1px dashed #d1d1d1;
  }

  &-handle {
    position: absolute;
    z-index: 9;
    user-select: none;

    &-top {
      top: -5px;
      left: 0;
      width: 100%;
      height: 10px;
    }

    &-right {
      top: 0;
      right: -5px;
      width: 10px;
      height: 100%;
    }

    &-bottom {
      bottom: -5px;
      left: 0;
      width: 100%;
      height: 10px;
    }

    &-left {
      top: 0;
      left: -5px;
      width: 10px;
      height: 100%;
    }

    &-topRight {
      top: -5px;
      right: -5px;
      z-index: 10;
      width: 20px;
      height: 20px;
    }

    &-bottomRight {
      right: -5px;
      bottom: -5px;
      z-index: 10;
      width: 20px;
      height: 20px;
    }

    &-bottomLeft {
      bottom: -5px;
      left: -5px;
      z-index: 10;
      width: 20px;
      height: 20px;
    }

    &-topLeft {
      top: -5px;
      left: -5px;
      z-index: 10;
      width: 20px;
      height: 20px;
    }
  }

  .@{resizable-prefix-cls}-handle {
    &-cursor-type {
      &-window {
        &.@{resizable-prefix-cls}-handle {
          &-top,
          &-bottom {
            cursor: ns-resize;
          }

          &-right,
          &-left {
            cursor: ew-resize;
          }
        }
      }

      &-grid {
        &.@{resizable-prefix-cls}-handle {
          &-top,
          &-bottom {
            cursor: row-resize;
          }

          &-right,
          &-left {
            cursor: col-resize;
          }
        }
      }
    }

    &-bottomRight,
    &-topLeft {
      cursor: nwse-resize;
    }

    &-bottomLeft,
    &-topRight {
      cursor: nesw-resize;
    }
  }

  &-disabled {
    .@{resizable-prefix-cls} {
      &-handle {
        pointer-events: none;
      }
    }
  }
}

//
// Progress bars
// --------------------------------------------------


// Bar animations
// -------------------------

// WebKit
@-webkit-keyframes progress-bar-stripes {
  from  { background-position: 40px 0; }
  to    { background-position: 0 0; }
}

// Spec and IE10+
@keyframes progress-bar-stripes {
  from  { background-position: 40px 0; }
  to    { background-position: 0 0; }
}



// Bar itself
// -------------------------

// Outer container
.progress {
  overflow: hidden;
  height: @line-height-computed;
  margin-bottom: @line-height-computed;
  background-color: @progress-bg;
  border-radius: @border-radius-base;
  .box-shadow(inset 0 1px 2px rgba(0,0,0,.1));
}

// Bar of progress
.progress-bar {
  float: left;
  width: 0%;
  height: 100%;
  font-size: @font-size-small;
  line-height: @line-height-computed;
  color: @progress-bar-color;
  text-align: center;
  background-color: @progress-bar-bg;
  .box-shadow(inset 0 -1px 0 rgba(0,0,0,.15));
  .transition(width .6s ease);
}

// Striped bars
//
// `.progress-striped .progress-bar` is deprecated as of v3.2.0 in favor of the
// `.progress-bar-striped` class, which you just add to an existing
// `.progress-bar`.
.progress-striped .progress-bar,
.progress-bar-striped {
  #gradient > .striped();
  background-size: 40px 40px;
}

// Call animation for the active one
//
// `.progress.active .progress-bar` is deprecated as of v3.2.0 in favor of the
// `.progress-bar.active` approach.
.progress.active .progress-bar,
.progress-bar.active {
  .animation(progress-bar-stripes 2s linear infinite);
}

// Account for lower percentages
.progress-bar {
  &[aria-valuenow="1"],
  &[aria-valuenow="2"] {
    min-width: 30px;
  }

  &[aria-valuenow="0"] {
    color: @gray-light;
    min-width: 30px;
    background-color: transparent;
    background-image: none;
    box-shadow: none;
  }
}



// Variations
// -------------------------

.progress-bar-success {
  .progress-bar-variant(@progress-bar-success-bg);
}

.progress-bar-info {
  .progress-bar-variant(@progress-bar-info-bg);
}

.progress-bar-warning {
  .progress-bar-variant(@progress-bar-warning-bg);
}

.progress-bar-danger {
  .progress-bar-variant(@progress-bar-danger-bg);
}

@triggerPrefixCls: rc-trigger-popup;

.@{triggerPrefixCls} {
  position: absolute;
  top: -9999px;
  left: -9999px;
  z-index: 1050;

  &-hidden {
    display: none;
  }

  .effect() {
    animation-duration: 0.3s;
    animation-fill-mode: both;
  }

  &-zoom-enter,
  &-zoom-appear {
    opacity: 0;
    animation-play-state: paused;
    animation-timing-function: cubic-bezier(0.18, 0.89, 0.32, 1.28);
    .effect();
  }

  &-zoom-leave {
    .effect();
    animation-play-state: paused;
    animation-timing-function: cubic-bezier(0.6, -0.3, 0.74, 0.05);
  }

  &-zoom-enter&-zoom-enter-active,
  &-zoom-appear&-zoom-appear-active {
    animation-name: rcTriggerZoomIn;
    animation-play-state: running;
  }

  &-zoom-leave&-zoom-leave-active {
    animation-name: rcTriggerZoomOut;
    animation-play-state: running;
  }

  &-arrow {
    z-index: 1;
    width: 0px;
    height: 0px;
    background: #000;
    border-radius: 100vw;
    box-shadow: 0 0 0 3px black;
  }

  @keyframes rcTriggerZoomIn {
    0% {
      transform: scale(0, 0);
      transform-origin: var(--arrow-x, 50%) var(--arrow-y, 50%);
      opacity: 0;
    }
    100% {
      transform: scale(1, 1);
      transform-origin: var(--arrow-x, 50%) var(--arrow-y, 50%);
      opacity: 1;
    }
  }
  @keyframes rcTriggerZoomOut {
    0% {
      transform: scale(1, 1);
      transform-origin: var(--arrow-x, 50%) var(--arrow-y, 50%);
      opacity: 1;
    }
    100% {
      transform: scale(0, 0);
      transform-origin: var(--arrow-x, 50%) var(--arrow-y, 50%);
      opacity: 0;
    }
  }

  // =============== Unique Container ===============
  &-unique-container {
    position: absolute;
    z-index: 0;
    box-sizing: border-box;
    border: 1px solid red;
    background: green;

    &-hidden {
      display: none;
    }

    &-visible {
      transition: all 0.1s;
    }
  }

  // Debug
  &-unique-controlled {
    border-color: rgba(0, 0, 0, 0.01) !important;
    background: transparent !important;
    z-index: 1;
  }

  // Motion Content
  &-motion-content {
    // Fade motion
    &-fade-appear {
      opacity: 0;
      animation-duration: 0.3s;
      animation-fill-mode: both;
      animation-timing-function: cubic-bezier(0.55, 0, 0.55, 0.2);
    }

    &-fade-appear&-fade-appear-active {
      animation-name: rcTriggerFadeIn;
    }

    @keyframes rcTriggerFadeIn {
      0% {
        opacity: 0;
      }
      100% {
        opacity: 1;
      }
    }
  }
}

