.@{empty-prefix-cls} {
  margin: 0 8px;
  font-size: @empty-font-size;
  line-height: @line-height-base;
  text-align: center;

  &-image {
    height: 100px;
    margin-bottom: 8px;

    img {
      height: 100%;
    }

    svg {
      height: 100%;
      margin: auto;
    }
  }

  &-footer {
    margin-top: 16px;
  }

  // antd internal empty style
  &-normal {
    margin: 32px 0;
    color: @disabled-color;

    .@{empty-prefix-cls}-image {
      height: 40px;
    }
  }

  &-small {
    margin: 8px 0;
    color: @disabled-color;

    .@{empty-prefix-cls}-image {
      height: 35px;
    }
  }
}

.@{empty-img-prefix-cls}-default {
  // not support the definition because the less variables have no meaning
  & when (@theme = dark) {
    &-ellipse {
      fill: @white;
      fill-opacity: 0.08;
    }

    &-path {
      &-1 {
        fill: #262626;
      }

      &-2 {
        fill: url('#linearGradient-1');
      }

      &-3 {
        fill: #595959;
      }

      &-4 {
        fill: #434343;
      }

      &-5 {
        fill: #595959;
      }
    }

    &-g {
      fill: #434343;
    }
  }
  & when not (@theme = dark) {
    &-ellipse {
      fill: #f5f5f5;
      fill-opacity: 0.8;
    }

    &-path {
      &-1 {
        fill: #aeb8c2;
      }

      &-2 {
        fill: url('#linearGradient-1');
      }

      &-3 {
        fill: #f5f5f7;
      }

      &-4 {
        fill: #dce0e6;
      }

      &-5 {
        fill: #dce0e6;
      }
    }

    &-g {
      fill: @white;
    }
  }
}

.@{empty-img-prefix-cls}-simple {
  // not support the definition because the less variables have no meaning
  & when (@theme = dark) {
    &-ellipse {
      fill: @white;
      fill-opacity: 0.08;
    }

    &-g {
      stroke: #434343;
    }

    &-path {
      fill: #262626;
      stroke: #434343;
    }
  }
  & when not (@theme = dark) {
    &-ellipse {
      fill: #f5f5f5;
    }

    &-g {
      stroke: #d9d9d9;
    }

    &-path {
      fill: #fafafa;
    }
  }
}

@import './rtl';

// Navigation stylings
.nav {
	a {
		color: @navigation-links-color;
		&:hover {
			color: #FFF;
		}
	}
}

.navbar{
	border: none;
	margin-bottom: 0;
	border-radius: 0;

	.navbar-text{
		h1,h2,h3,h4,h5,h6{
			margin: 0px 15px;
		}
	}

}

.navbar-default{
	.box-shadow(0 1px 0 @default-grey-600);
}

.navbar-right{
	float: right!important;
	display: block;
}

.navbar-left{
	float: left!important;
	display: block;
}



// Standalone Pills
//
// Extend Pills to show validation states
// <p><b>Deprecated</b> - The states will be removed in the future
// please don't use it anymore</p>
// <p><b>Experimental</b> - Only use states standalone with for static text right now!</p>
//
// Markup:
//   <div class="nav-pill">Text</div>
//



//Color States are deprecated, please remove them soon

.nav-pill-variant(default; transparent; @dark-grey; @dark-grey-800;);
.nav-pill-variant(has-success; transparent; @state-success-bg; @state-success-bg;);
.nav-pill-variant(has-info; transparent; @state-info-bg; @state-info-bg);
.nav-pill-variant(has-warning; transparent; @state-warning-bg; @state-warning-bg;);
.nav-pill-variant(has-error; transparent; @state-danger-bg; @state-danger-bg;);


// MIXINS
// ==================================================================

// Standalone Pills with States

.nav-pill-variant(@state; @background; @border; @color) {
  .nav-pill-style(){
     display: block;
      padding: 10px 15px;
      position: relative;
      border-radius: @nav-pills-border-radius;
      margin-left: 2px;
      background: @background;
      color: @color;
      float: left;
      border: 1px solid @border;

    &.active,
    & a:hover,
    & a:focus{
            background: lighten(@border, 30%);
            color: darken(@color, 5%)
    }

  }

    .nav-pill{
      .nav-pill-state() when (@state = default) {
        .nav-pill-style;
      }
      .nav-pill-state(){
        &.@{state}{
          .nav-pill-style;
        }
      }
      .nav-pill-state;
    }

}

@import '../../base.less';

@import './_var.less';

.@{prefix}-form {
  background-color: @bg-color-container;

  .@{prefix}-form__item {
    display: flex;
    box-sizing: border-box;
    padding: @form-item-vertical-padding @form-item-horizontal-padding;
    position: relative;

    &:not(:last-child)::after {
      .hairline-bottom(@form-item-border-color);

      left: @form-item-border-left-space;
      right: @form-item-border-right-space;
    }

    &-help,
    &-extra {
      display: flex;
      font-size: @font-size-s;
      margin: 0;
      width: 100%;
      height: auto;
      min-height: 20px;
      margin-top: 4px;
    }

    &-help {
      color: @text-color-disabled;
    }

    &--error {
      color: @error-color-6;
    }

    &--warning {
      color: @warning-color-5;
    }

    &-wrap {
      width: 100%;
    }

    &--top {
      display: flex;
      flex-direction: column;
    }
  }

  &--top {
    align-items: center;
  }

  &__label {
    float: left;
    padding-right: 16px;
    vertical-align: middle;
    font-size: @form-label-font-size;
    line-height: 24px;
    color: @text-color-primary;
    box-sizing: border-box;
    word-break: break-all;

    &--top {
      padding-bottom: 8px;
    }

    &--left {
      text-align: left;
    }

    &--right {
      text-align: right;
    }

    &--required:not(.@{prefix}-form__label--required-right) {
      label::before {
        display: inline-block;
        margin-right: calc(@spacer / 2);
        color: @error-color-6;
        line-height: 20px;
        content: '*';
      }
    }

    &--required-right {
      label::after {
        display: inline-block;
        margin-left: calc(@spacer / 2);
        color: @error-color-6;
        line-height: 20px;
        content: '*';
      }
    }

    &--colon {
      label::after {
        content: ':';
        position: relative;
        margin: 0 2px;
      }
    }
  }

  &__controls {
    display: flow-root;
    position: relative;

    &-content {
      display: flex;
      align-items: center;
      min-height: 24px;
    }

    &--left {
      justify-content: flex-start;
    }

    &--right {
      justify-content: flex-end;
    }
  }

  // 覆盖一些组件样式
  .@{prefix}-cell,
  .@{prefix}-input,
  .@{prefix}-textarea,
  .@{prefix}-upload {
    padding: 0;
  }
}

@import '../custom.less';

@notify-prefix-cls: ~'@{css-prefix}notify';

.@{notify-prefix-cls} {
  @apply fixed;
  @apply ~'z-[1101]';
  @apply ~"max-w-[theme('spacing.108')]";
  @apply w-full;
  @apply box-border;
  @apply transition-all duration-300;
  @apply overflow-hidden;
  @apply whitespace-nowrap;
  @apply p-6;
  @apply rounded-sm;
  @apply text-sm;
  @apply flex;
  @apply flex-row;
  @apply items-start;
  @apply shadow-xl;
  @apply rounded;
  @apply bg-color-bg-1;

  &.top-left {
    @apply ~'left-2.5';
    @apply top-6;
  }

  &.bottom-left {
    @apply ~'left-2.5';
    @apply bottom-6;
  }

  &.top-right {
    @apply ~'right-2.5';
    @apply top-6;
  }

  &.bottom-right {
    @apply ~'right-2.5';
    @apply bottom-6;
  }

  & &__title {
    @apply font-bold;
    @apply text-sm;
    @apply text-color-text-primary;
    @apply ~'leading-6.5';
    @apply whitespace-nowrap;
    @apply overflow-hidden;
    @apply text-ellipsis;
  }

  & &__icon {
    @apply text-color-brand;
  }

  & &__content {
    @apply m-0;
    @apply p-0;
    @apply text-sm;
    @apply text-color-text-primary;
    @apply break-all;
    @apply whitespace-pre-wrap;
  }

  & &__closebtn {
    @apply cursor-pointer;
    @apply text-color-brand;
    @apply absolute;
    @apply ~'top-1/2';
    @apply ~'right-2.5';
    @apply ~'-translate-y-2/4';
  }

  & &__icon-zone {
    @apply w-6;
    @apply h-6;
    @apply text-2xl;
  }

  & &__message-zone {
    @apply w-full;
    @apply ~'ml-2.5';
    @apply min-w-0;
  }

  & &__close-zone {
    @apply w-4;
    @apply h-4;
    @apply text-base;
    @apply cursor-pointer;
  }

  &--info &__icon-zone {
    @apply fill-color-info-primary;
  }

  &--warning &__icon-zone {
    @apply fill-color-warning;
  }

  &--error &__icon-zone {
    @apply fill-color-error;
  }

  &--success &__icon-zone {
    @apply fill-color-success;
  }

  &__icon-zone &__icon-status {
    @apply relative;
    @apply -top-1;
  }

  &--no-close &__message-zone {
    @apply w-full;
  }

  &__message-zone &__title-wrapper {
    @apply h-6;
    @apply leading-6;
    @apply mb-2;
    @apply text-color-text-primary;
  }

  &__message-zone &__content-wrapper {
    @apply h-auto;
    @apply leading-6;
    @apply ~'max-h-[theme(spacing.24)]';
    @apply overflow-y-auto;
  }

  &__close-zone &__icon-close {
    @apply relative;
    @apply ~'top-0.5';
  }

  &--no-icon &__message-zone {
    @apply w-full;
  }
}

@import '../custom.less';

@grid-radio-prefix-cls: ~'@{css-prefix}grid-radio';

// radio
.@{grid-radio-prefix-cls} {
  @apply inline-block;
  @apply select-none;
  @apply cursor-pointer;

  &.size__small,
  &.size__mini {
    @apply text-base;
    @apply flex;
    @apply justify-center;
    @apply items-center;

    > input {
      & + .@{grid-radio-prefix-cls}__icon {
        @apply text-base;

        > svg {
          @apply block;
        }
      }
    }
  }

  > input {
    @apply hidden;

    & + .@{grid-radio-prefix-cls}__icon {
      @apply relative;
      @apply inline-block;
      width: 1em;
      height: 1em;
      @apply align-middle;
      @apply rounded-full;
      @apply text-base;

      > svg {
        @apply fill-color-icon-secondary;
        @apply align-top;

        &:hover {
          @apply fill-color-icon-hover;
        }

        &:active {
          @apply fill-color-icon-active;
        }

        &.icon-radio-selected {
          @apply hidden;
        }
      }
    }

    &:checked + .@{grid-radio-prefix-cls}__icon {
      > svg {
        &.icon-radio {
          @apply hidden;
        }

        &.icon-radio-selected {
          @apply inline-block;
          @apply fill-color-brand;

          &:hover {
            @apply fill-color-icon-hover;
          }

          &:active {
            @apply fill-color-icon-active;
          }
        }
      }

      & + .@{grid-radio-prefix-cls}__label {
        @apply text-color-brand;
      }
    }
  }

  & &__label {
    @apply pl-2;
    @apply align-middle;
    @apply inline-block;
  }

  & + & {
    @apply ~'ml-2.5';
  }

  &.is__disabled {
    @apply cursor-not-allowed;

    > input {
      & + .@{grid-radio-prefix-cls}__icon {
        > svg {
          @apply fill-color-text-disabled;

          path:last-child {
            @apply fill-color-border-disabled;
          }
        }

        &:before {
          @apply border-color-bg-2;
          @apply bg-color-bg-2;
        }

        & + .@{grid-radio-prefix-cls}__label {
          @apply text-color-text-disabled;
        }
      }

      &:checked + .@{grid-radio-prefix-cls}__icon {
        > svg,
        > svg:hover,
        > svg:active {
          @apply fill-color-brand-disabled;

          > path:first-child {
            @apply fill-color-brand-disabled;
          }
        }
      }
    }
  }
}

@import '../mixins/progress.less';
@import '../custom.less';

@progress-prefix-cls: ~'@{css-prefix}progress';

.@{progress-prefix-cls} {
  @apply relative;
  @apply leading-none;

  &--line {
    @apply flex;
    @apply items-center;
  }

  &.is-success {
    .progress-status(theme('colors.color.success.DEFAULT'));
  }

  &.is-warning {
    .progress-status(theme('colors.color.warning.DEFAULT'));
  }

  &.is-exception {
    .progress-status(theme('colors.color.error.DEFAULT'));
  }

  &__text {
    @apply text-xs;
    @apply text-color-text-primary;
    @apply inline-block;
    @apply align-middle;
    @apply ml-2;
    @apply leading-none;

    i {
      @apply align-middle;
      @apply inline-block;
    }
  }

  &--circle,
  &--dashboard {
    @apply inline-block;

    .@{progress-prefix-cls}__text {
      @apply absolute;
      @apply ~'top-1/2';
      @apply left-0;
      @apply w-full;
      @apply text-center;
      @apply m-0;
      @apply translate-x-0 ~'-translate-y-1/2';

      i {
        @apply align-middle;
        @apply inline-block;
      }
    }
  }

  &--without-text &__text {
    @apply hidden;
  }

  &--without-text &-bar {
    @apply pr-0;
    @apply mr-0;
    @apply block;
  }

  &--text-inside &-bar {
    @apply pr-0;
    @apply mr-0;
  }

  &-bar {
    @apply pr-12;
    @apply w-full;
    @apply -mr-12;
    @apply box-border;

    &__outer {
      @apply ~'h-1.5';
      @apply rounded-full;
      @apply bg-color-bg-3;
      @apply overflow-hidden;
      @apply relative;
      @apply align-middle;
    }

    &__inner {
      @apply absolute;
      @apply left-0;
      @apply top-0;
      @apply h-full;
      @apply bg-color-brand;
      @apply text-right;
      @apply rounded-full;
      @apply leading-none;
      @apply whitespace-nowrap;
      transition: width 0.6s ease;

      &::after {
        @apply content-[''];
        @apply h-full;
      }
    }

    &__innerText {
      @apply text-color-text-inverse;
      @apply text-xs;
      @apply mr-3;
    }

    &,
    &__inner::after,
    &__innerText {
      @apply inline-block;
      @apply align-middle;
    }
  }
}

@-webkit-keyframes progress {
  0% {
    @apply bg-left-top;
  }

  100% {
    background-position: 32px 0;
  }
}

@keyframes progress {
  0% {
    @apply bg-left-top;
  }

  100% {
    background-position: 32px 0;
  }
}

@import '../custom.less';

@grid-prefix-cls: ~'@{css-prefix}grid';

// tooltip
.@{grid-prefix-cls}__tooltip-wrapper {
  @apply hidden;
  @apply absolute;
  @apply -top-full;
  @apply -left-full;
  @apply text-xs;
  max-width: 400px;
  @apply rounded;
  @apply py-2 px-3;
  @apply whitespace-normal;
  word-break: break-word;
  @apply shadow-sm;
  @apply text-color-text-secondary;
  font-family: Helvetica, Arial, 'Microsoft YaHei', sans-serif;
  @apply pointer-events-none;
  @apply ~'z-[4000]';

  &.is__visible {
    @apply block;
  }

  &.is__arrow {
    .@{grid-prefix-cls}__tooltip-arrow {
      @apply block;
    }
  }

  &.placement__top {
    .@{grid-prefix-cls}__tooltip-arrow {
      @apply -bottom-3;

      &:before {
        top: -7px;
      }
    }
  }

  &.placement__bottom {
    .@{grid-prefix-cls}__tooltip-arrow {
      @apply ~'-top-3';

      &:before {
        @apply -top-1;
      }
    }
  }

  &.theme__light {
    @apply bg-color-bg-1;
    @apply border border-solid border-color-border;

    &.placement__top {
      .@{grid-prefix-cls}__tooltip-arrow {
        @apply border-t-color-border;

        &:before {
          @apply border-t-color-bg-1;
        }
      }
    }

    &.placement__bottom {
      .@{grid-prefix-cls}__tooltip-arrow {
        @apply border-b-color-border;

        &:before {
          @apply border-b-color-bg-1;
        }
      }
    }
  }

  &.theme__dark {
    @apply bg-color-bg-3;
    @apply text-color-text-inverse;

    &.placement__top {
      .@{grid-prefix-cls}__tooltip-arrow {
        @apply border-t-color-border;

        &:before {
          @apply border-t-color-border;
        }
      }
    }

    &.placement__bottom {
      .@{grid-prefix-cls}__tooltip-arrow {
        @apply border-b-color-border;

        &:before {
          @apply border-b-color-border;
        }
      }
    }
  }

  .@{grid-prefix-cls}__tooltip-arrow {
    @apply hidden;
    @apply absolute;
    @apply border-transparent;
    border-width: 6px;
    @apply border-solid;
    @apply ~'left-1/2';

    &:before {
      @apply content-[''];
      @apply absolute;
      @apply border-transparent;
      border-width: 5px;
      @apply border-solid;
      left: -5px;
    }
  }

  &.@{grid-prefix-cls}__valid-error {
    @apply bg-color-error;
    @apply text-color-text-inverse;
  }
}

@import '../custom.less';

@filter-box-prefix-cls: ~'@{css-prefix}filter-box';

.@{filter-box-prefix-cls} {
  @apply w-fit;
  @apply max-w-full;
  @apply h-7;
  @apply leading-7;
  @apply rounded;
  @apply bg-color-bg-2;
  @apply text-color-text-primary;
  @apply py-1;
  @apply ~'px-1.5';
  @apply flex;
  @apply items-center;
  @apply text-xs;

  &.@{filter-box-prefix-cls}--medium {
    @apply h-8;
    @apply leading-8;
    @apply px-2;
    @apply text-sm;
  }

  &:hover {
    @apply bg-color-info-primary-subtler;
  }

  &.disabled {
    @apply cursor-not-allowed;

    .title label {
      @apply text-color-text-disabled;
    }

    .value {
      @apply text-color-text-secondary;
    }

    svg.filter-box-icon {
      @apply fill-color-icon-disabled;
      @apply cursor-not-allowed;
    }
  }

  .title {
    height: inherit;
    @apply ~'leading-[inherit]';

    label {
      @apply ~'max-w-[theme(spacing.28)]';
      @apply inline-block;
      @apply overflow-hidden;
      @apply text-ellipsis;
      @apply whitespace-nowrap;
      @apply text-color-none-active;
      @apply mr-1;
    }

    &.active label {
      @apply text-color-brand;
    }

    svg {
      @apply w-4;
      @apply h-4;
      @apply mr-1;
      @apply fill-color-icon-placeholder;
      @apply relative;
      @apply -top-px;
      @apply align-super;

      &:hover {
        @apply fill-color-brand;
      }
    }
  }

  .value {
    @apply ~'max-w-[theme(spacing.28)]';
    height: inherit;
    @apply mr-1;
    @apply overflow-hidden;
    @apply text-ellipsis;
    @apply whitespace-nowrap;
    @apply ~'leading-[inherit]';
    @apply text-color-text-primary;

    &.placeholder {
      @apply text-color-text-placeholder;
    }
  }

  .filter-box-icon {
    @apply w-3;
    @apply h-3;
    @apply cursor-pointer;
    @apply fill-color-fill-secondary;
    @apply ~'transition-[transform]' duration-300;

    &.is-reverse {
      @apply rotate-180;
    }
  }

  .filter-icon-close {
    @apply w-4;
    @apply h-4;
    @apply cursor-pointer;
    @apply fill-color-none-hover;
    @apply shrink-0;

    &:hover {
      @apply fill-color-fill-secondary;
    }
  }

  &.is-blank {
    @apply bg-transparent;
  }
}

@import '../custom.less';

@popover-prefix-cls: ~'@{css-prefix}popover';
@popper-prefix-cls: ~'@{css-prefix}popper';

.@{popover-prefix-cls}.@{popper-prefix-cls} {
  @apply absolute;
  @apply bg-color-bg-1;
  @apply text-color-icon-primary;
  @apply rounded;
  @apply border-none;
  @apply py-3 px-4;
  @apply ~'z-[2000]';
  @apply ~'leading-5.5';
  @apply text-justify;
  @apply text-sm;
  @apply shadow-md;
  @apply break-all;

  .popper__arrow,
  .popper__arrow::after {
    @apply absolute;
    @apply block;
    @apply w-0;
    @apply h-0;
    @apply border-transparent;
    @apply border-solid;
  }

  .popper__arrow,
  .@{popper-prefix-cls} .popper__arrow {
    @apply border-4;
  }

  .popper__arrow::after {
    @apply ~"content-['']";
  }

  &[x-placement^='top'] {
    @apply mb-3;

    .popper__arrow {
      @apply -bottom-1;
      @apply ~'left-1/2';
      margin-right: 3px;
      @apply border-solid;
      @apply border-b-color-bg-1;
      @apply border-l-color-bg-1;
      @apply rounded-bl-sm;
      transform: rotate(315deg);
    }
  }

  &[x-placement^='bottom'] {
    @apply mt-3;

    .popper__arrow {
      @apply -top-1;
      @apply ~'left-1/2';
      margin-right: 3px;
      @apply border-solid;
      @apply border-b-color-bg-1;
      @apply border-l-color-bg-1;
      @apply rounded-bl-sm;
      transform: rotate(135deg);
    }
  }

  &[x-placement^='right'] {
    @apply ml-3;

    .popper__arrow {
      @apply ~'top-1/2';
      @apply -left-1;
      margin-bottom: 3px;
      @apply border-solid;
      @apply border-b-color-bg-1;
      @apply border-l-color-bg-1;
      @apply rounded-bl-sm;
      @apply rotate-45;
    }
  }

  &[x-placement^='left'] {
    @apply mr-3;

    .popper__arrow {
      @apply ~'top-1/2';
      @apply -right-1;
      margin-bottom: 3px;
      @apply border-solid;
      @apply border-b-color-bg-1;
      @apply border-l-color-bg-1;
      @apply rounded-bl-sm;
      transform: rotate(225deg);
    }
  }

  .@{popover-prefix-cls}__plain {
    @apply ~'py-4.5' px-5;
  }

  .@{popover-prefix-cls}__title {
    @apply text-color-text-primary;
    @apply text-sm;
    @apply leading-none;
    @apply mb-2;
  }

  &:focus,
  &:focus:active,
  .@{popover-prefix-cls}__reference:focus:hover,
  .@{popover-prefix-cls}__reference:focus:not(.focusing) {
    @apply outline-0;
  }
}

.@{popover-prefix-cls} {
  &__reference {
    @apply inline-block;
  }
}

@import '../mixins/common.less';
@import '../custom.less';

@checkbox-button-prefix-cls: ~'@{css-prefix}checkbox-button';

.@{checkbox-button-prefix-cls} {
  @apply relative;
  @apply inline-block;

  &:nth-child(n) &__inner {
    @apply border-l border-l-color-border;
    @apply rounded-tl-sm rounded-tr-none rounded-br-none rounded-bl-sm;
    @apply -mr-px;
  }

  &:last-child &__inner {
    @apply rounded-tl-none rounded-tr-sm rounded-br-sm rounded-bl-none;
  }

  &.is-checked {
    .@{checkbox-button-prefix-cls}__inner {
      @apply text-color-text-inverse;
      @apply bg-color-brand;
      @apply border-color-border-focus;
    }

    &:first-child .@{checkbox-button-prefix-cls}__inner {
      @apply border-l-color-border-focus;
      @apply shadow-none;
    }
  }

  &.is-disabled {
    .@{checkbox-button-prefix-cls}__inner {
      @apply text-color-text-secondary;
      @apply cursor-not-allowed;
      @apply bg-none;
      @apply bg-color-bg-2;
      @apply border-color-border;
      @apply shadow-none;
    }

    &:first-child .@{checkbox-button-prefix-cls}__inner {
      @apply border-l-color-border;
    }
  }

  &__inner {
    @apply relative;
    @apply inline-block;
    @apply whitespace-nowrap;
    @apply align-middle;
    @apply outline-0;
    @apply leading-none;
    @apply font-medium;
    @apply cursor-pointer;
    @apply bg-color-bg-1;
    @apply border border-solid border-color-border;
    @apply border-l-0;
    @apply text-color-text-primary;
    @apply appearance-none;
    @apply text-center;
    @apply box-border;
    @apply m-0;
    @apply transition-all duration-300 ease-linear;
    @apply py-3 px-5;
    @apply text-xs;
    @apply ~'min-w-[theme(spacing.20)]';
    @apply rounded-none;
    .user-select(none);

    &.is-round {
      @apply py-3 px-5;
    }

    &:hover {
      @apply text-color-brand-hover;
    }
  }

  &__original {
    @apply opacity-0;
    @apply outline-0;
    @apply absolute;
    @apply m-0;
    @apply ~'-z-[1]';
  }

  &--medium &__inner {
    @apply ~'py-2.5' px-5;
    @apply text-sm;
    @apply rounded-none;

    &.is-round {
      @apply ~'py-2.5' px-5;
    }
  }

  &--small &__inner {
    @apply py-2 px-4;
    @apply text-xs;
    @apply rounded-none;

    &.is-round {
      @apply py-2 px-4;
    }
  }

  &--mini &__inner {
    @apply py-1 px-4;
    @apply text-xs;
    @apply rounded-none;

    &.is-round {
      @apply py-1 px-4;
    }
  }
}

@import '../custom.less';

@badge-prefix-cls: ~'@{css-prefix}badge';
@badge-wrapper-prefix-cls: ~'@{css-prefix}badge__wrapper';

.@{badge-prefix-cls} {
  @apply inline-block;
  @apply ~'min-w-[theme(spacing.4)]';
  @apply h-5;
  @apply leading-5;
  @apply rounded-xl;
  @apply py-0 px-1;
  @apply text-xs;
  @apply font-bold;
  @apply text-color-text-inverse;
  @apply bg-color-error;
  @apply align-baseline;
  @apply whitespace-nowrap;
  @apply text-center;

  &&--max {
    @apply py-0 ~'px-1.5';
    @apply rounded-xl;
  }

  &&--default {
    @apply ~'w-1.5';
    @apply ~'h-1.5';
    @apply ~'min-w-[auto]';
    @apply bg-color-error;
    @apply inline-block;
    @apply align-top;
    @apply p-0;
    @apply rounded-full;
  }

  &&--primary {
    @apply bg-color-brand;
  }

  &&--success {
    @apply bg-color-success;
  }

  &&--warning {
    @apply bg-color-warning;
  }

  &&--danger {
    @apply bg-color-error;
  }

  &&--info {
    @apply bg-color-info-secondary;
  }

  &:empty {
    @apply hidden;
  }

  .btn & {
    @apply relative;
    @apply -top-px;
  }

  a,
  a:hover {
    @apply text-color-text-inverse;
    @apply no-underline;
  }
}

a.badge {
  &:hover,
  &:focus {
    @apply text-color-text-inverse;
    @apply no-underline;
    @apply cursor-pointer;
  }
}

a.list-group-item.active > .badge,
.nav-pills > .active > a > .badge {
  @apply text-color-brand;
  @apply bg-color-bg-1;
}

.nav-pills > li > a > .badge {
  margin-left: 3px;
}

.@{badge-wrapper-prefix-cls} {
  @apply relative;

  .@{badge-prefix-cls} {
    @apply absolute;
    @apply ~'top-1/2';
    @apply translate-x-1 -translate-y-1/2;
    @apply ~'min-w-[theme(spacing.4)]';
    @apply h-4;
    @apply leading-4;
    @apply text-xs;

    &__content-text {
      @apply relative;
    }
  }

  .@{badge-prefix-cls}--default {
    @apply absolute;
    @apply ~'top-1/2';
    @apply translate-x-1 ~'-translate-y-2/4';
    @apply ~'min-w-[auto]';
    @apply ~'w-1.5';
    @apply ~'h-1.5';
    @apply bg-color-error;
  }
}

@import '../custom.less';

@autocomplete-prefix-cls: ~'@{css-prefix}autocomplete';
@icon-loading-prefix-cls: ~'@{css-prefix}icon-loading';
@popper-prefix-cls: ~'@{css-prefix}popper';
@scrollbar-prefix-cls: ~'@{css-prefix}scrollbar';

.@{autocomplete-prefix-cls} {
  @apply relative;
  @apply inline-block;
  @apply w-full;

  &.show-auto-width {
    @apply w-full;
  }

  &-suggestion {
    @apply rounded;
    @apply bg-color-bg-1;
    @apply box-border;
    @apply shadow-md;

    .@{scrollbar-prefix-cls} {
      @apply rounded;
      @apply pt-1;
    }

    &__wrap {
      @apply ~'max-h-[theme(spacing.72)]';
      @apply box-border;
    }

    // 兼容ie10-ie11
    @media screen and (-ms-high-contrast: active),
    (-ms-high-contrast: none) {
      &__wrap {
        margin-bottom: -17px !important;
        @apply ~'pb-1.5';
      }
    }

    &__list {
      @apply m-0;
      @apply p-0;
    }

    & &__list-item {
      @apply py-0 px-3;
      @apply m-0;
      @apply leading-8;
      @apply text-color-text-primary;
      @apply text-xs;
      @apply list-none;
      @apply whitespace-nowrap;
      @apply overflow-hidden;
      @apply text-ellipsis;
      @apply cursor-pointer;

      &.highlighted,
      &:hover {
        @apply bg-color-bg-3;
      }

      &.divider {
        @apply ~'mt-1.5';
        @apply border-t border-t-color-border;

        &:last-child {
          @apply ~'-mb-1.5';
        }
      }

      &:only-of-type {

        &,
        &:hover {
          @apply bg-color-bg-3;
        }
      }
    }

    &.is-loading &__list-loading {
      @apply text-center;
      @apply h-8;
      @apply leading-8;
      @apply text-xl;

      svg {
        @apply fill-color-brand;
      }

      &::after {
        @apply inline-block;
        @apply content-[''];
        @apply h-full;
        @apply align-middle;
      }

      &:hover {
        @apply bg-color-bg-1;
      }
    }

    &.is-loading {
      .@{icon-loading-prefix-cls} {
        @apply align-middle;
      }
    }

    &.@{popper-prefix-cls}[x-placement^='bottom'] {
      @apply ~'mt-0.5';
    }
  }
}

@import '../custom.less';

@user-prefix-cls: ~'@{css-prefix}user';
@tag-prefix-cls: ~'@{css-prefix}tag';
@input-prefix-cls: ~'@{css-prefix}input';
@select-prefix-cls: ~'@{css-prefix}select';
@svg-prefix-cls: ~'@{css-prefix}svg';

.@{user-prefix-cls} {
  &.mini {
    height: 30px;
  }

  & &__select {
    @apply w-full;

    .@{input-prefix-cls} {
      .@{svg-prefix-cls} {
        @apply fill-color-text-placeholder;
        @apply w-4;
        @apply h-4;

        &:hover {
          @apply fill-color-brand-hover;
        }
      }

      &__inner {
        @apply pl-10;
      }

      &__prefix {
        @apply pl-3;
      }

      &.is-disabled .@{svg-prefix-cls} {
        @apply fill-color-icon-disabled;
      }
    }

    .@{select-prefix-cls}__input {
      @apply h-5;
    }
    .@{select-prefix-cls}__tags {
      &.is-showicon {
      }
      .@{tag-prefix-cls} {
        @apply ~'mt-0.5' mr-1 ~'mb-0.5' ml-0;
        @apply text-xs;
      }
    }

    &.@{select-prefix-cls}__multiple {
      .@{input-prefix-cls}__suffix {
        @apply ~"top-1/2";
        @apply ~"-translate-y-2/4";
      }
    }
  }

  & &__ghost {
    &.@{tag-prefix-cls} {
      @apply bg-color-brand-disabled;
    }
  }

  &_select {
    max-width: ~'calc(50% - theme(spacing.1))';
    @apply w-auto;
    @apply whitespace-nowrap;
    @apply overflow-hidden;
    @apply text-ellipsis;

    &.left {
      @apply float-left;
      @apply mr-1;
    }

    &.right {
      float: right;
      @apply ml-1;
    }
  }

  &__select-dropdown {
    @apply flex;
    @apply justify-start;
    @apply items-center;
  }

  .@{select-prefix-cls} {
    .@{tag-prefix-cls} {
      @apply ~"max-w-[theme('spacing.36')]";
    }

    .@{input-prefix-cls}.is-show-close {
      .icon-close {
        @apply mr-0;
      }

      .@{input-prefix-cls}__inner {
        @apply pr-12;
      }
    }
  }

  &.draggableClass {
    .@{select-prefix-cls} {
      &__tags > span:not(.is-disabled),
      &__tags > span:not(.is-disabled) > span {
        @apply inline-block;
      }
    }
  }
}

@import '../custom.less';

@upload-prefix-cls: ~'@{css-prefix}upload';
@upload-dragger-prefix-cls: ~'@{css-prefix}upload-dragger';

.@{upload-dragger-prefix-cls} {
  width: 360px;
  height: 180px;
  @apply bg-color-bg-1;
  @apply border-2 border-dashed border-color-text-placeholder;
  @apply rounded;
  @apply box-border;
  @apply text-center;
  @apply overflow-hidden;
  @apply flex;
  @apply flex-col;
  @apply justify-center;
  @apply items-center;

  &:hover {
    @apply border-color-border-hover;
  }

  &:active {
    @apply border-color-border-hover;
    @apply bg-color-bg-2;
  }

  &.is-dragover {
    @apply relative;
    @apply border-color-error;

    &::after {
      @apply content-[''];
      @apply w-full;
      @apply h-full;
      @apply absolute;
      border: 5px solid theme('colors.color.error.disabled');
    }
  }

  .icon-fileupload {
    @apply w-20;
    @apply h-20;
    @apply fill-color-text-primary;
  }

  .@{upload-prefix-cls}__text {
    @apply text-color-text-primary;
    @apply text-xs;
    @apply text-center;
    @apply mt-2;

    em {
      @apply text-color-brand;
      @apply not-italic;
    }

    &-tips {
      @apply text-xs;
      @apply mt-2;
      @apply text-color-text-secondary;
    }
  }

  & + .@{upload-prefix-cls}__tip {
    @apply text-center;
  }

  & ~ .@{upload-prefix-cls}__files {
    @apply border-t border-t-color-border;
    margin-top: 7px;
    padding-top: 5px;
  }
}

.@{upload-prefix-cls} {
  &.is-disabled {
    .@{upload-prefix-cls}-dragger {
      @apply cursor-not-allowed;
      @apply border-color-border;

      &:active {
        @apply bg-color-bg-1;
        @apply border-color-border;
      }

      .icon-fileupload {
        @apply fill-color-text-disabled;
      }

      .@{upload-prefix-cls}__text {
        @apply text-color-text-disabled;

        em {
          @apply text-color-brand-disabled;
        }

        &-tips {
          @apply text-color-text-disabled;
        }
      }
    }
  }
}

